import React, {
  forwardRef,
  useEffect,
  useImperativeHandle,
  useMemo,
  useRef,
} from "react";
import {
  Animated,
  Easing,
  Text,
  View,
} from "react-native";
import { Box } from "../../ui"; // Gluestack Box
import type {
  ProgressBarProps,
} from "./ProgressBar.types";
import { resolveThemeTokenForNative } from '../../Factory/helpers/style';
export * from './ProgressBar.types';

const BAR_HEIGHT = 10;

export const ProgressBar = forwardRef<any, ProgressBarProps>(
  (props, ref) => {
    const {
      value = null,
      color = resolveThemeTokenForNative('primary'),
      unit = "%",
      showValue = true,
      mode = "determinate",
      unstyled = false,
      displayValueTemplate,
      style,
      testID,
    } = props;

    const rootRef = useRef<View>(null);
    const progressAnim = useRef(new Animated.Value(0)).current;
    const indeterminateAnim = useRef(new Animated.Value(0)).current;

    /**
     * PrimeReact ref API
     */
    useImperativeHandle(ref, () => ({
      getElement: () => rootRef.current,
    }));

    /**
     * Determinate animation
     */
    useEffect(() => {
      if (mode !== "determinate") return;
      if (value === null || value === undefined) return;

      const numeric =
        typeof value === "string" ? Number(value) : value;

      if (Number.isNaN(numeric)) return;

      Animated.timing(progressAnim, {
        toValue: Math.max(0, Math.min(100, numeric)),
        duration: 400,
        easing: Easing.out(Easing.cubic),
        useNativeDriver: false,
      }).start();
    }, [value, mode]);

    /**
     * Indeterminate animation
     */
    useEffect(() => {
      if (mode !== "indeterminate") return;

      indeterminateAnim.setValue(0);

      const loop = Animated.loop(
        Animated.timing(indeterminateAnim, {
          toValue: 1,
          duration: 1200,
          easing: Easing.linear,
          useNativeDriver: false,
        }),
      );

      loop.start();
      return () => loop.stop();
    }, [mode]);

    const widthInterpolated = progressAnim.interpolate({
      inputRange: [0, 100],
      outputRange: ["0%", "100%"],
    });

    const indeterminateTranslate = indeterminateAnim.interpolate({
      inputRange: [0, 1],
      outputRange: ["-40%", "100%"],
    });

    const label = useMemo(() => {
      if (!showValue) return null;

      if (displayValueTemplate) {
        return displayValueTemplate(value);
      }

      if (value === null || value === undefined) return null;

      return `${value}${unit}`;
    }, [value, unit, showValue, displayValueTemplate]);

    return (
      <Box
        ref={rootRef}
        testID={testID}

        style={{
          height:BAR_HEIGHT,
          overflow:"hidden",
          borderRadius:BAR_HEIGHT / 2,
          backgroundColor:unstyled ? undefined : resolveThemeTokenForNative('gray.200'),
          ...style
        }}
      >
        {mode === "determinate" && (
          <Animated.View
            style={{
              height: "100%",
              width: widthInterpolated,
              backgroundColor: color,
            }}
          />
        )}

        {mode === "indeterminate" && (
          <Animated.View
            style={{
              position: "absolute",
              height: "100%",
              width: "40%",
              backgroundColor: color,
              transform: [{ translateX: indeterminateTranslate }],
            }}
          />
        )}

        {label != null && (
          <Box

            style={{
              position:"absolute",
              inset:0,
              alignItems:"center",
              justifyContent:"center",
            }}
          >
            {typeof label === "string" ||
            typeof label === "number" ? (
              <Text
                style={{
                  fontSize: 11,
                  fontWeight: "600",
                  color: "#000",
                }}
              >
                {label}
              </Text>
            ) : (
              label
            )}
          </Box>
        )}
      </Box>
    );
  },
);

ProgressBar.displayName = "ProgressBar";
